evaluators.evaluation_logic:
const checkpoints = [];

const quoteRequests = JSON.parse(localStorage.getItem('quote_requests') || '[]');
const servicePackages = JSON.parse(localStorage.getItem('service_packages') || '[]');

const targetParticipants = 50;
const maxBudget = 15000;

// Find qualifying VR training packages in Training & Simulation that can handle 50 participants under $15k
const qualifyingPackages = servicePackages.filter(sp => {
  if (!sp || sp.status !== 'active') return false;
  if (sp.service_category_id !== 'training_simulation') return false;
  if (sp.technology !== 'vr') return false;
  if (sp.experience_type !== 'training') return false;
  if (typeof sp.base_price !== 'number' || sp.base_price > maxBudget) return false;
  const minP = typeof sp.min_participants === 'number' ? sp.min_participants : null;
  const maxP = typeof sp.max_participants === 'number' ? sp.max_participants : null;
  const minOk = (minP == null) || (minP <= targetParticipants);
  const maxOk = (maxP == null) || (maxP >= targetParticipants);
  return minOk && maxOk;
});

// Determine the cheapest qualifying package(s)
let cheapestPrice = null;
let cheapestPackageIds = [];
qualifyingPackages.forEach(sp => {
  if (typeof sp.base_price !== 'number') return;
  if (cheapestPrice == null || sp.base_price < cheapestPrice) {
    cheapestPrice = sp.base_price;
    cheapestPackageIds = [sp.id];
  } else if (sp.base_price === cheapestPrice) {
    cheapestPackageIds.push(sp.id);
  }
});

// Quote requests for qualifying packages with exactly 50 participants
const qualifyingQuoteRequests = quoteRequests.filter(qr => {
  if (!qr || qr.request_type !== 'service_package' || !qr.service_package_id) return false;
  if (qr.number_of_participants !== targetParticipants) return false;
  return qualifyingPackages.some(sp => sp.id === qr.service_package_id);
});

// CP1 (0.6): User submitted at least one quote request for a qualifying VR safety package WITH 50 participants
checkpoints.push({
  passed: qualifyingQuoteRequests.length > 0,
  weight: 0.6
});

// CP2 (0.4): At least one qualifying quote request is for the CHEAPEST qualifying package
const cheapestQuote = qualifyingQuoteRequests.some(qr => cheapestPackageIds.includes(qr.service_package_id));
checkpoints.push({
  passed: cheapestPackageIds.length > 0 && cheapestQuote,
  weight: 0.4
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const projectBriefs = JSON.parse(localStorage.getItem('project_briefs') || '[]');
const servicePackages = JSON.parse(localStorage.getItem('service_packages') || '[]');

const maxBudget = 40000;
const minReach = 100000;

// Qualifying AR product launch campaigns under budget with required reach in Marketing & Brand Experiences
const qualifyingPackages = servicePackages.filter(sp => {
  if (!sp || sp.status !== 'active') return false;
  if (sp.service_category_id !== 'marketing_brand') return false;
  if (sp.technology !== 'ar') return false;
  if (sp.experience_type !== 'product_launch') return false;
  if (typeof sp.base_price !== 'number' || sp.base_price > maxBudget) return false;
  if (typeof sp.expected_reach !== 'number' || sp.expected_reach < minReach) return false;
  return true;
});

const qualifyingPackageIds = qualifyingPackages.map(sp => sp.id);

// Project briefs that target one of the qualifying campaigns
const qualifyingBriefs = projectBriefs.filter(pb => {
  if (!pb || !pb.related_service_package_id) return false;
  return qualifyingPackageIds.includes(pb.related_service_package_id);
});

// CP1 (1.0): User created at least one project brief for a qualifying AR product launch campaign
checkpoints.push({
  passed: qualifyingBriefs.length > 0,
  weight: 1.0
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const caseStudies = JSON.parse(localStorage.getItem('case_studies') || '[]');
const collectionItems = JSON.parse(localStorage.getItem('saved_collection_items') || '[]');

// Consider only saved case studies with VR technology in the target industries
const csById = {};
caseStudies.forEach(cs => { if (cs && cs.id) csById[cs.id] = cs; });

// Group qualifying items by collection
const groups = {};
collectionItems.forEach(it => {
  if (!it || it.item_type !== 'case_study') return;
  const cs = csById[it.item_id];
  if (!cs) return;
  if (cs.technology !== 'vr') return;
  if (!['retail', 'healthcare', 'education'].includes(cs.industry)) return;
  if (!groups[it.collection_id]) groups[it.collection_id] = [];
  groups[it.collection_id].push({ item: it, cs });
});

let hasCompleteCollection = false;
Object.keys(groups).forEach(colId => {
  const items = groups[colId];
  if (!items || items.length < 3) return;
  const industries = new Set(items.map(x => x.cs.industry));
  if (industries.has('retail') && industries.has('healthcare') && industries.has('education')) {
    hasCompleteCollection = true;
  }
});

// CP1 (1.0): At least one collection contains VR case studies covering all three industries in the SAME collection
checkpoints.push({
  passed: hasCompleteCollection,
  weight: 1.0
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const configs = JSON.parse(localStorage.getItem('experience_configurations') || '[]');
const configModules = JSON.parse(localStorage.getItem('experience_configuration_modules') || '[]');
const modules = JSON.parse(localStorage.getItem('experience_modules') || '[]');
const quoteRequests = JSON.parse(localStorage.getItem('quote_requests') || '[]');

const modulesById = {};
modules.forEach(m => { if (m && m.id) modulesById[m.id] = m; });

// Candidate configurations in New York with audience 500–800, total between 25k and 35k, and marked as submitted
const candidateConfigs = configs.filter(ec => {
  if (!ec) return false;
  if (ec.is_submitted_for_quote !== true) return false;
  const city = (ec.location_city || '').toLowerCase();
  const display = (ec.location_display || '').toLowerCase();
  const isNY = city.includes('new york') || display.includes('new york');
  if (!isNY) return false;
  const minA = typeof ec.audience_min === 'number' ? ec.audience_min : null;
  const maxA = typeof ec.audience_max === 'number' ? ec.audience_max : null;
  if (minA == null || maxA == null) return false;
  if (minA < 500 || maxA > 800) return false;
  if (typeof ec.estimated_total !== 'number') return false;
  if (ec.estimated_total < 25000 || ec.estimated_total > 35000) return false;
  return true;
});

let hasQualifyingConfig = false;

candidateConfigs.forEach(ec => {
  if (!ec || hasQualifyingConfig) return;
  const ecId = ec.id;
  const lines = configModules.filter(cm => cm && cm.experience_configuration_id === ecId);
  if (!lines.length) return;

  let interactiveCount = 0;
  let photoBoothCount = 0;

  lines.forEach(line => {
    const mod = modulesById[line.experience_module_id];
    if (!mod) return;
    const qty = typeof line.quantity === 'number' && line.quantity > 0 ? line.quantity : 1;
    if (mod.module_type === 'interactive_zone') interactiveCount += qty;
    if (mod.module_type === 'photo_booth') photoBoothCount += qty;
  });

  const hasEnoughZones = interactiveCount >= 2;
  const hasPhotoBooth = photoBoothCount >= 1;

  const hasQuote = quoteRequests.some(qr => {
    return qr && qr.request_type === 'popup_configuration' && qr.experience_configuration_id === ecId;
  });

  if (hasEnoughZones && hasPhotoBooth && hasQuote) {
    hasQualifyingConfig = true;
  }
});

// CP1 (1.0): At least one New York configuration meets audience, pricing, module composition, and quote-submission requirements
checkpoints.push({
  passed: hasQualifyingConfig,
  weight: 1.0
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const events = JSON.parse(localStorage.getItem('events') || '[]');
const eventRegistrations = JSON.parse(localStorage.getItem('event_registrations') || '[]');

const eventsById = {};
events.forEach(e => { if (e && e.id) eventsById[e.id] = e; });

const sixtyDaysMs = 60 * 24 * 60 * 60 * 1000;

const qualifyingRegistrations = eventRegistrations.filter(er => {
  if (!er || !er.event_id) return false;
  const ev = eventsById[er.event_id];
  if (!ev) return false;
  // Event criteria
  if (ev.topic !== 'xr_strategy') return false;
  if (ev.level !== 'beginner') return false;
  if (typeof ev.price !== 'number' || ev.price > 300) return false;
  // Ticket count
  if (er.number_of_tickets !== 1) return false;
  // Timing: event start within 60 days after registration
  const start = new Date(ev.start_datetime);
  const regDate = new Date(er.registered_at);
  if (isNaN(start.getTime()) || isNaN(regDate.getTime())) return false;
  const diffMs = start.getTime() - regDate.getTime();
  if (diffMs < 0 || diffMs > sixtyDaysMs) return false;
  return true;
});

// CP1 (1.0): At least one registration matches topic, level, price, timing, and ticket-count requirements
checkpoints.push({
  passed: qualifyingRegistrations.length > 0,
  weight: 1.0
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const jobs = JSON.parse(localStorage.getItem('jobs') || '[]');
const applications = JSON.parse(localStorage.getItem('job_applications') || '[]');

const jobsById = {};
jobs.forEach(j => { if (j && j.id) jobsById[j.id] = j; });

const qualifyingApplications = applications.filter(app => {
  if (!app || !app.job_id) return false;
  const job = jobsById[app.job_id];
  if (!job || !job.is_active) return false;
  // Mid-level XR role in UX/Product design departments
  if (job.seniority_level !== 'mid_level') return false;
  if (!job.is_xr_related) return false;
  if (!(job.department === 'design' || job.department === 'ux_ui_design')) return false;
  // Experience roughly 3–5 years
  if (typeof job.experience_min_years !== 'number' || typeof job.experience_max_years !== 'number') return false;
  if (job.experience_min_years < 3) return false;
  if (job.experience_max_years > 5) return false;
  // Title should reference UX Designer or Product Designer
  const title = (job.title || '').toLowerCase();
  if (!(title.includes('ux designer') || title.includes('product designer'))) return false;
  // CV must NOT be uploaded
  if (app.cv_uploaded) return false;
  return true;
});

// CP1 (1.0): At least one application matches all role and no-upload requirements
checkpoints.push({
  passed: qualifyingApplications.length > 0,
  weight: 1.0
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const inquiries = JSON.parse(localStorage.getItem('contact_inquiries') || '[]');

const qualifyingInquiries = inquiries.filter(ci => {
  if (!ci) return false;
  // Inquiry type
  if (ci.inquiry_type !== 'agency_partner') return false;
  // Areas of interest includes white-label XR production
  if (!Array.isArray(ci.areas_of_interest) || !ci.areas_of_interest.includes('white_label_xr_production')) return false;
  // Budget at or above 60,000
  if (typeof ci.budget_minimum !== 'number' || ci.budget_minimum < 60000) return false;
  // Regions must cover US and EU (via allowed enums)
  if (!Array.isArray(ci.regions)) return false;
  const regions = ci.regions;
  const hasUS = regions.includes('united_states') || regions.includes('north_america');
  const hasEU = regions.includes('europe') || regions.includes('european_union');
  if (!hasUS || !hasEU) return false;
  return true;
});

// CP1 (1.0): At least one inquiry matches agency partner, white-label XR production, budget, and regional focus
checkpoints.push({
  passed: qualifyingInquiries.length > 0,
  weight: 1.0
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const articles = JSON.parse(localStorage.getItem('articles') || '[]');
const collectionItems = JSON.parse(localStorage.getItem('saved_collection_items') || '[]');

const articlesById = {};
articles.forEach(a => { if (a && a.id) articlesById[a.id] = a; });

// Group saved articles by collection and count topics
const groups = {};
collectionItems.forEach(it => {
  if (!it || it.item_type !== 'article') return;
  const art = articlesById[it.item_id];
  if (!art) return;
  if (!groups[it.collection_id]) {
    groups[it.collection_id] = { museumCount: 0, retailCount: 0 };
  }
  if (art.topic === 'museums_exhibitions') groups[it.collection_id].museumCount += 1;
  if (art.topic === 'retail') groups[it.collection_id].retailCount += 1;
});

let hasQualifyingReadingList = false;
Object.keys(groups).forEach(colId => {
  const g = groups[colId];
  if (g.museumCount >= 2 && g.retailCount >= 1) {
    hasQualifyingReadingList = true;
  }
});

// CP1 (1.0): At least one collection contains ≥2 museum/exhibition articles AND ≥1 retail article
checkpoints.push({
  passed: hasQualifyingReadingList,
  weight: 1.0
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
